  "patterns": [
    {
      "id": "AP-001",
      "title": "In-Memory-Only Auth Lockout",
      "root_cause": "Authentication lockout mechanism uses process-local in-memory map with no distributed synchronization, trivially bypassed in multi-instance deployments",
      "detection_signature": {
        "semgrep": "pattern: 'map[$TYPE]$TYPE2' used for rate limiting or lockout without Redis/DB persistence",
        "grep": "map\\[string\\]time\\.Time.*lock|Lock.*map\\[string\\]"
      },
      "severity": "HIGH",
      "confirmed_instances": [
        {
          "file": "src/core/auth/lock.go",
          "line": 23,
          "function": "UserLock",
          "finding": "p8-001"
        }
      ],
      "untested_candidates": []
    },
    {
      "id": "AP-002",
      "title": "Filter-Before-Check Ordering Bug",
      "root_cause": "Security filter (e.g., GroupFilter regex) is applied to data persistence path but NOT to the authorization decision path, allowing unfiltered data to influence access control",
      "detection_signature": {
        "grep": "filterGroup|GroupFilter.*populate|AdminGroup.*Contains"
      },
      "severity": "HIGH",
      "confirmed_instances": [
        {
          "file": "src/pkg/oidc/helper.go",
          "line": 396,
          "function": "userInfoFromClaims",
          "finding": "p8-002"
